14	const COMPONENT_BASE_PREMIUM = 25;
15	
16	const BASE_PREMIUM_BY_ITEM: Record<Item["kind"], number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: COMPONENT_BASE_PREMIUM,
22	  moonstone: COMPONENT_BASE_PREMIUM,
23	};
24	
25	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
26	const PROCESSING_FEE = 5;
27	
28	function basePremiumFor(item: Item): number {
29	  return BASE_PREMIUM_BY_ITEM[item.kind];
30	}
31	
32	function quoteStep(step: QuoteStep) {
33	  const basePremium = step.items.reduce((sum, item) => sum + basePremiumFor(item), 0);
34	  const surcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
35	  const premium = Math.ceil(basePremium + surcharge + PROCESSING_FEE);
36	  return { kind: "quote" as const, premium };
37	}
38	
39	export function processScenario(scenario: Scenario): ScenarioResult {
40	  const results = scenario.steps.map(quoteStep);
41	  return { results };
42	}
